// C2: Acting Components
instance FirstJointActingComponent : DTDFVocab:ActingComponent [
    base:desc "Permanent‑magnet synchronous motor and its gear transmission (gearbox and cycloidal gearbox) that drive the first joint of the MABI MAX‑100 serial industrial robot."
]

// C3: Physical sensing components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor monitoring motor electrical current."
    DTDFVocab:producedData MotorCurrentSignal
]

instance MotorEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Position encoder attached to motor shaft."
    DTDFVocab:producedData MotorAngleSignal
]

instance GearboxEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Position encoder attached to gearbox output."
    DTDFVocab:producedData GearboxAngleSignal
]

// C4: Physical‑to‑virtual interaction
instance MotorCurrentSignal : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorAngleSignal : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoderSensor
]

instance GearboxAngleSignal : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoderSensor
]

// C10: Models/Data
instance SysMLMotorGearboxModel : DTDFVocab:Model [
    base:desc "SysML component definition of motor and gearbox for the first joint."
    DTDFVocab:inputTo SysMLTool
]

instance SimulinkMotorModel : DTDFVocab:Model [
    base:desc "MathWorks Simulink model of the permanent‑magnet synchronous motor."
    DTDFVocab:inputTo SimulinkTool
]

instance SimulinkGearboxModel : DTDFVocab:Model [
    base:desc "Simulink model of the gear transmission including gearbox and cycloidal gearbox."
    DTDFVocab:inputTo SimulinkTool
]

instance SimulinkCoulombViscousFrictionModel : DTDFVocab:Model [
    base:desc "Simulink representation of Coulomb and viscous friction components."
    DTDFVocab:inputTo SimulinkTool
]

instance SimulinkStribeckFrictionModel : DTDFVocab:Model [
    base:desc "Simulink model of Stribeck friction."
    DTDFVocab:inputTo SimulinkTool
]

instance SimulinkDahlFrictionModel : DTDFVocab:Model [
    base:desc "Simulink representation of Dahl friction model."
    DTDFVocab:inputTo SimulinkTool
]

instance SimulinkLuGreFrictionModel : DTDFVocab:Model [
    base:desc "Simulink representation of LuGre friction model."
    DTDFVocab:inputTo SimulinkTool
]

// Data instances
instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Measured electric motor current."
    DTDFVocab:inputTo MQTTBrokerEnabler
    DTDFVocab:fromData MotorCurrentSignal
]

instance MotorAngleData : DTDFVocab:Data [
    base:desc "Measured motor shaft angle via encoder."
    DTDFVocab:inputTo MQTTBrokerEnabler
    DTDFVocab:fromData MotorAngleSignal
]

instance GearboxAngleData : DTDFVocab:Data [
    base:desc "Measured gearbox output angle via encoder."
    DTDFVocab:inputTo MQTTBrokerEnabler
    DTDFVocab:fromData GearboxAngleSignal
]

instance TorqueData : DTDFVocab:Data [
    base:desc "Estimated motor torque derived from sensor data."
    DTDFVocab:inputTo MQTTBrokerEnabler
    DTDFVocab:fromData MotorCurrentSignal
]

instance AngularVelocityData : DTDFVocab:Data [
    base:desc "Estimated angular velocity derived from encoder data."
    DTDFVocab:inputTo MQTTBrokerEnabler
    DTDFVocab:fromData MotorAngleSignal
]

instance AccelerationData : DTDFVocab:Data [
    base:desc "Estimated angular acceleration derived from encoder data."
    DTDFVocab:inputTo MQTTBrokerEnabler
    DTDFVocab:fromData MotorAngleSignal
]

